-- quest_6016_main_ep16.md (19 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","text":"かつて世界を揺るがした大天使の侵攻。それは遠い過去の出来事となっていた。四つの首都は完全に復興し、レガリアの城壁は以前よりも堅牢に、イスハークの黄金のドームは眩いばかりに輝いている。平和な時代。だが——胸の奥に、何かが引っかかっていた。","next":"text_peace","choices":[{"label":"続ける","next":"text_peace"}]},"text_peace":{"type":"text","bg_key":"bg_road_day","text":"英霊が退けた大天使たちの記憶は、語り継がれている。だが——神そのものには、誰も届いていない。いつまた、天から裁きが降ってくるかわからない。何かを——探さなければならない気がしていた。その「何か」が、まだわからなかった。","next":"text_border_town","choices":[{"label":"続ける","next":"text_border_town"}]},"text_border_town":{"type":"text","bg_key":"bg_road_day","text":"足は自然と、国境の町に向かっていた。ローランドとマルカンドの境にある小さな町。ここは交易路の中継地で、旅人や商人が行き交っている。町外れの丘に登った時——不思議な光が目に入った。草むらの中に、何かが埋もれている。","next":"text_strange_pull","choices":[{"label":"続ける","next":"text_strange_pull"}]},"text_strange_pull":{"type":"text","bg_key":"bg_road_day","text":"草を掻き分けると、苔むした石碑が現れた。風化した表面に、微かな紋様が刻まれている。どこかの古代文明のものか。だが——見覚えがある気がした。いや、見覚えではない。体が——この石碑を「知っている」と訴えている。","next":"text_stele_discovery","choices":[{"label":"続ける","next":"text_stele_discovery"}]},"text_stele_discovery":{"type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_tense","text":"石碑の前に立った。紋様が淡く光り始めた。手を伸ばすと——石碑が温かい。生きているような温もり。まるで、中に誰かがいるかのような。導かれるように——石碑に、手を触れた。","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"type":"text","bg_key":"bg_heroic_stele","text":"触れた瞬間——意識が飛んだ。目の前が真っ白になり、次の瞬間、自分が知らない場所に立っていた。荒野。遠くに山脈。見たことのない星空。——これは、記憶だ。自分の記憶ではない。誰かの——遠い過去の記憶。","next":"text_vision_start","choices":[{"label":"続ける","next":"text_vision_start"}]},"text_vision_start":{"type":"text","bg_key":"bg_heroic_stele","text":"記憶の中で、一人の戦士が剣を振るっていた。顔は見えない。だが——その背中を知っている。魂の奥底で、繋がっている感覚。この人物は——かつて、この世界を救った英霊。神の裁きに立ち向かい、人間の未来を勝ち取った存在。そして——自分は、その継承者だった。","next":"text_vision_hero","choices":[{"label":"続ける","next":"text_vision_hero"}]},"text_vision_hero":{"type":"text","bg_key":"bg_heroic_stele","text":"英霊の声が聞こえた。天使の声とは違う。温かく、人間の言葉だった。「……やっと、目覚めたか。　待っていた。ずっと、待っていた。　お前の中に、俺の力の欠片が眠っている。　だが今のままでは、まだ足りない。　世界に散らばった石碑を巡れ。　俺が遺した武具を集めろ。　全てが揃った時——お前は、神に届く」","next":"text_vision_end","choices":[{"label":"続ける","next":"text_vision_end"}]},"text_vision_end":{"type":"text","bg_key":"bg_heroic_stele","text":"「石碑は四つの都市の近くにある。　イスハーク、龍京、出雲、レガリア——　それぞれに、俺の記憶と遺産が眠っている」英霊の姿が薄れていく。「……時間がない。奴らも気づき始めている。　お前が継承者であることに。　——急げ」","next":"text_awakening","choices":[{"label":"続ける","next":"text_awakening"}]},"text_awakening":{"type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_calm","text":"意識が戻った。石碑の前に、膝をついていた。どのくらいの時間が経ったのかわからない。だが——全身に、微かな力が満ちている。今まで感じたことのない力。英霊の力の、ほんの欠片。","next":"text_inheritance","choices":[{"label":"続ける","next":"text_inheritance"}]},"text_inheritance":{"type":"text","bg_key":"bg_heroic_stele","text":"自分が——世界を救った英霊の継承者。信じがたい話だ。だが、体が知っている。この力は本物だ。四つの都市に、石碑と遺産が眠っている。全てを集めれば——神に届く力が手に入る。立ち上がった。新たな旅の目的が、定まった。","next":"text_ambush_warning","choices":[{"label":"続ける","next":"text_ambush_warning"}]},"text_ambush_warning":{"type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_crisis","text":"その時——空気が変わった。英霊が言っていた。「奴らも気づき始めている」と。空が暗くなる。だが雲ではない。黒い翼の群れが、上空を覆い始めた。堕天使——天から追放された者たち。神に仕えながらも、穢れに染まった存在。","next":"text_fallen_descent","choices":[{"label":"続ける","next":"text_fallen_descent"}]},"text_fallen_descent":{"type":"text","bg_key":"bg_road_day","text":"堕天使の群れが、丘の上に降り立った。天使とは異なる、黒い翼と歪んだ光。だが——力は本物だ。石碑を壊そうとしている。あるいは——継承者を、ここで潰そうとしている。","next":"text_fallen_taunt","choices":[{"label":"続ける","next":"text_fallen_taunt"}]},"text_fallen_taunt":{"type":"text","bg_key":"bg_road_day","speaker_name":"堕天使","text":"堕天使の一体が嗤った。「英霊ノ継承者カ。　マタ、人間ガ分ヲ弁エズニ足掻クノカ。　先代モ同ジダッタ。強カッタガ——所詮ハ人間。　滅ビル運命ハ変ワラナイ」黒い翼が広がった。嗤いながら——襲いかかってきた。","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","text":"堕天使の群れが急襲！英霊の石碑を守り抜け！","enemy_group_id":"216","next":"text_aftermath","battle_success_next":"text_aftermath","choices":[{"label":"続ける","next":"text_aftermath"}]},"text_aftermath":{"type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_calm","text":"堕天使を退けた。石碑は無事だ。紋様がまだ淡く光っている。まるで——「よくやった」と言っているかのように。石碑に手を当てた。今度は幻視は来ない。だが——温かさが、手のひらに伝わった。","next":"text_guidance","choices":[{"label":"続ける","next":"text_guidance"}]},"text_guidance":{"type":"text","bg_key":"bg_road_day","text":"四つの都市に散らばった石碑と遺産。イスハークのピラミッドに——護符。龍京の沖合の無人島に——剣。出雲の山奥の秘境に——鎧。レガリアの郊外の遺跡に——最後の記憶。全てを集めた時、神に届く力が手に入る。英霊の導きに従い、旅に出る。","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"type":"end","bg_key":"bg_road_day","text":"自分が何者であるかを知った。英霊の継承者——かつて世界を救った者の後継。まだ力は足りない。だが、道は示された。四つの都市に眠る遺産を集め、英霊が果たせなかった決着をつける。丘を下り、旅立った。石碑の光が背中を押すように、静かに瞬いていた。","params":{"type":"end","result":"success","bg":"bg_road_day"},"next":"end_failure","choices":[]},"end_failure":{"type":"end","bg_key":"bg_road_day","text":"堕天使の爪に引き裂かれ、地に伏した。石碑の光が——消えていく。英霊の遺産は、また長い眠りにつくのだろうか。","params":{"type":"end","result":"failure"},"choices":[]}}}'::jsonb, rewards = '{"gold":3000,"exp":400,"reputation":20}'::jsonb WHERE id = 6016;

-- quest_6017_main_ep17.md (18 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","text":"英霊の導きに従い、イスハークへ向かった。黄金都市はかつての輝きを取り戻し、市場には商人たちの活気ある声が響いている。目的地は街の外——砂漠の中のピラミッドだ。","next":"text_ishaq","choices":[{"label":"続ける","next":"text_ishaq"}]},"text_ishaq":{"type":"text","bg_key":"bg_desert","text":"イスハークの東に、古代のピラミッドが聳えている。マルカンドの建国よりも遥か昔——名もなき文明が築いた巨大な石造りの墓所。観光名所として知られているが、内部の大半は未踏査のまま残されている。その奥に——英霊の石碑がある。","next":"text_pyramid","choices":[{"label":"続ける","next":"text_pyramid"}]},"text_pyramid":{"type":"text","bg_key":"bg_catacombs","text":"ピラミッドの入口を抜け、内部に入った。松明の光が石壁に揺れる。壁面には古代の壁画が描かれていた。星の配置。人間の営み。そして——翼を持つ存在との戦い。この文明も、かつて神と戦ったのかもしれない。","next":"text_hidden_passage","choices":[{"label":"続ける","next":"text_hidden_passage"}]},"text_hidden_passage":{"type":"text","bg_key":"bg_catacombs","text":"奥へ進むと、行き止まりに突き当たった。だが——壁の一部に、石碑と同じ紋様が刻まれている。手を当てると、壁が音を立てて動き始めた。砂が崩れ落ち、隠し通路が現れた。空気が変わった。古い空気。何千年も閉じ込められていた空気。その奥から、微かな光が漏れている。","next":"text_chamber","choices":[{"label":"続ける","next":"text_chamber"}]},"text_chamber":{"type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","text":"通路の先に、広い部屋があった。天井が高い。壁面全体に紋様が刻まれている。部屋の中央に——石碑が立っていた。国境の町で見つけたものと同じ紋様。だが、こちらの方が大きく、光が強い。中に眠る記憶が——呼んでいる。","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"type":"text","bg_key":"bg_pyramid_chamber","text":"石碑の表面に文字が浮かび上がった。古代の言語。読めないはずなのに——意味が伝わる。「此処に、英霊の記憶を封じる。　継承者よ。触れよ。　我が戦いを追体験し、力の欠片を受け継げ」","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"type":"text","bg_key":"bg_pyramid_chamber","text":"石碑に手を触れた。前回と同じように、意識が飛んだ。だが今度は——より深く、より鮮明に。目を開けると、見知らぬ場所に立っていた。ここは——先代の英霊の記憶の中だ。","next":"text_memory_start","choices":[{"label":"続ける","next":"text_memory_start"}]},"text_memory_start":{"type":"text","bg_key":"bg_memory_oasis","text":"記憶の中の風景が広がった。砂漠の中のオアシス。椰子の木が揺れ、泉が陽光を反射している。だが——空気が張り詰めていた。このオアシスで、英霊は何かと戦ったのだ。","next":"text_memory_oasis","choices":[{"label":"続ける","next":"text_memory_oasis"}]},"text_memory_oasis":{"type":"text","bg_key":"bg_memory_oasis","text":"記憶が再生される。先代の英霊は、このオアシスで追い詰められていた。水を求めて辿り着いた泉の底から——冥界の門が開いたのだ。泉の水が黒く染まる。地面が裂け、暗い霧が噴き出した。その霧の中から——冥王が姿を現した。","next":"text_hades_appear","choices":[{"label":"続ける","next":"text_hades_appear"}]},"text_hades_appear":{"type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_battle_strong","text":"黒い霧が人の形を取った。蒼白い肌。深い闇を湛えた瞳。黒い衣を纏い、手には闇の錫杖を持っている。冥王ハデス——死者の国を統べる神。生命そのものを奪い取る力の持ち主。記憶の中の存在だが——殺意は本物だ。","next":"text_hades_voice","choices":[{"label":"続ける","next":"text_hades_voice"}]},"text_hades_voice":{"type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","text":"ハデスが口を開いた。低く、冷たく、地の底から響くような声。「また来たか、英霊の欠片よ。　先代も同じ顔をしていた。　死を恐れぬ目。だが——」錫杖が地面を突いた。地面に亀裂が走る。「死を恐れぬことと、　死を超えることは違う」","next":"text_hades_challenge","choices":[{"label":"続ける","next":"text_hades_challenge"}]},"text_hades_challenge":{"type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","text":"「冥府の門を越えられるか、試してやろう。　先代は——越えた。　だが代償に、寿命の半分を差し出した。　お前はどうだ？　同じ覚悟があるか？」冥王の錫杖が光り、暗い霧が渦を巻いた。","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_memory_oasis","bgm":"bgm_spot_final_boss","text":"冥王ハデスとの戦闘！記憶の中の死神を打ち倒し、英霊の遺産を勝ち取れ！","enemy_group_id":"9050","next":"text_hades_defeat","battle_success_next":"text_hades_defeat","choices":[{"label":"続ける","next":"text_hades_defeat"}]},"text_hades_defeat":{"type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","text":"ハデスの錫杖が砕けた。黒い霧が晴れ、オアシスに陽光が戻る。「……見事だ。先代と同じ力を感じる。　いや——それ以上かもしれん」ハデスの姿が薄れていく。「覚えておけ。死は終わりではない。　次の始まりだ。　——お前が来た時、冥府の門は開いている」","next":"text_talisman","choices":[{"label":"続ける","next":"text_talisman"}]},"text_talisman":{"type":"text","bg_key":"bg_pyramid_chamber","text":"意識が現実に戻った。石碑の足元に——光る物体が落ちていた。古い護符。暗い輝きを放つ石が嵌め込まれている。手に取ると、冷たいが——力が込められている。冥王の護符。英霊がハデスから勝ち取った遺産の一つ。","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","text":"ピラミッドを出ると、砂漠の夕陽が眩しかった。護符を懐に収めた。四つの遺産のうち、一つを手にした。残りは三つ。龍京の無人島に剣。出雲の秘境に鎧。レガリアの遺跡に——最後の記憶。","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"type":"end","bg_key":"bg_road_day","text":"冥王ハデスの試練を乗り越え、護符を手に入れた。英霊の記憶は、鮮烈だった。あの英霊もまた、一人の人間として神に抗い続けたのだ。自分はその続きを歩いている。次の石碑を目指して、旅を続ける。","params":{"type":"end","result":"success","bg":"bg_road_day"},"next":"end_failure","choices":[]},"end_failure":{"type":"end","bg_key":"bg_memory_oasis","text":"冥王の霧に呑み込まれた。意識が暗闇に沈んでいく。記憶の中で——ハデスの声が遠くから聞こえた。「まだ、早かったか……」","params":{"type":"end","result":"failure"},"choices":[]}}}'::jsonb, rewards = '{"gold":3500,"exp":450,"reputation":25}'::jsonb WHERE id = 6017;

-- quest_6018_main_ep18.md (18 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","text":"英霊の導きに従い、龍京へ向かった。華龍の首都は活気に満ち、港には大陸各地からの交易船が停泊している。だが目的は都市の中ではない。龍京の漁師から聞いた話——沖合に、誰も近づかない小さな無人島があるという。「光る石がある」と、古い漁師が教えてくれた。","next":"text_port","choices":[{"label":"続ける","next":"text_port"}]},"text_port":{"type":"text","bg_key":"bg_road_day","text":"龍京の港で小舟を借りた。漁師たちは島の方角を指差して首を振った。「あの島には行かねぇ方がいい。　海が荒れる。磁石が狂う。　……帰ってこなかった奴もいる」忠告を聞き流し、船を出した。","next":"text_voyage","choices":[{"label":"続ける","next":"text_voyage"}]},"text_voyage":{"type":"text","bg_key":"bg_road_day","text":"港を出て半日。漁師の言う通り、島に近づくと海が荒れ始めた。波が高くなり、風向きが突然変わる。だが——石碑の紋様が腕に浮かんだ。光る紋様が、正しい方角を示している。波を切り、島に辿り着いた。","next":"text_island_arrival","choices":[{"label":"続ける","next":"text_island_arrival"}]},"text_island_arrival":{"type":"text","bg_key":"bg_island","bgm":"bgm_quest_tense","text":"無人島は想像よりも小さかった。白い砂浜と、背の高い熱帯の樹木。鳥の声が響いている。虫の音が重なる。一見すると平穏な島だが——空気に、微かな緊張が含まれている。島の中央に向かって、獣道を進んだ。","next":"text_jungle","choices":[{"label":"続ける","next":"text_jungle"}]},"text_jungle":{"type":"text","bg_key":"bg_island","text":"密林を掻き分けて進むと、木々の間に古い石段が見えた。苔むした石段を登ると、開けた場所に出た。石造りの祭壇のような構造物。その中央に——石碑が立っていた。陽光を浴びて、紋様が輝いている。","next":"text_ruins","choices":[{"label":"続ける","next":"text_ruins"}]},"text_ruins":{"type":"text","bg_key":"bg_island","text":"祭壇の周囲に、古代の彫刻が並んでいた。剣を振るう戦士。盾を構える兵士。そして——血に染まった戦場に立つ、鎧の神の姿。この島は、戦の神を祀る古代の聖域だったのだ。","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"type":"text","bg_key":"bg_heroic_stele","text":"石碑に近づいた。表面に文字が浮かび上がる。「此処に、英霊の記憶を封じる。　継承者よ。触れよ。　戦神の試練を越え、力の欠片を受け継げ」深呼吸をして——石碑に手を触れた。","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"type":"text","bg_key":"bg_heroic_stele","text":"意識が飛んだ。視界が暗くなり——次の瞬間、深い森の中に立っていた。英霊の記憶。夜だ。雨が降っている。体のどこかが——痛い。","next":"text_memory_forest","choices":[{"label":"続ける","next":"text_memory_forest"}]},"text_memory_forest":{"type":"text","bg_key":"bg_memory_forest","text":"記憶が再生される。英霊は、雨の森を一人で走っていた。肩から血が流れている。足を引きずっている。背後から——重い足音が迫っていた。走っても走っても、距離が縮まる。木の陰に身を隠した。息を殺して、追手が通り過ぎるのを待った。だが——足音が、目の前で止まった。","next":"text_ares_appear","choices":[{"label":"続ける","next":"text_ares_appear"}]},"text_ares_appear":{"type":"text","bg_key":"bg_memory_forest","bgm":"bgm_battle_strong","text":"木の陰から見上げると——男が立っていた。赤銅色の鎧。使い込まれた大剣を片手で提げている。人間と同じ背丈。だが——纏う気配が違う。雨に濡れた赤い髪。傷だらけの顔。戦い続けることだけが生きがいだと言わんばかりの、獣のような目をしていた。軍神アレス——戦そのものを体現した神。","next":"text_ares_voice","choices":[{"label":"続ける","next":"text_ares_voice"}]},"text_ares_voice":{"type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","text":"アレスが木の幹を蹴った。英霊の隠れていた木が、根元から折れた。「見つけたぞ、傭兵。　三日も追いかけさせやがって。　まともに立てもしねぇくせに、よく逃げ回る」大剣の切っ先で、英霊の顎を持ち上げた。「だが——その目は気に入った。　諦めてねぇ目だ。折れた剣でもまだ斬れると思ってる目だ」","next":"text_ares_challenge","choices":[{"label":"続ける","next":"text_ares_challenge"}]},"text_ares_challenge":{"type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","text":"「お前の英霊は何度も逃げた。何度も隠れた。　だが——追い詰めるたびに刃を向けてきた。　ボロボロの体で、折れかけの剣で」アレスが大剣を構えた。雨粒が刀身を伝い、赤い光が滲む。「技も策も使い果たした後に残るもの。　それが本物の強さだ。　——お前にもそれがあるか、見せてみろ」","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_memory_forest","bgm":"bgm_spot_final_boss","text":"軍神アレスとの戦闘！満身創痍の中、戦の神に立ち向かえ！","enemy_group_id":"9051","next":"text_ares_defeat","battle_success_next":"text_ares_defeat","choices":[{"label":"続ける","next":"text_ares_defeat"}]},"text_ares_defeat":{"type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","text":"泥の中で剣を振り上げ——アレスの鎧の隙間を突いた。軍神がよろめき、片膝をついた。「……ハッ。やっぱりそうだ。　お前らは追い詰められた時が一番怖ぇ」アレスが立ち上がり、破顔した。血が流れているのに——嬉しそうに笑っている。「気に入った。俺の剣を持っていけ。　——次に会う時は、逃げずに最初から来いよ」笑い声を残して、アレスの姿が雨に溶けた。","next":"text_sword","choices":[{"label":"続ける","next":"text_sword"}]},"text_sword":{"type":"text","bg_key":"bg_island","text":"意識が現実に戻った。石碑の足元に——剣が刺さっていた。重厚な刀身。赤い光を帯びた鍔。手に取ると、ずっしりとした重みがある。だが振ると——驚くほど速く、正確に空を切った。軍神の剣。英霊がアレスから勝ち取った遺産の一つ。","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","text":"島を出て、龍京に戻った。手の中の剣が、赤い光を微かに放っている。四つの遺産のうち、また一つを手にした。英霊の記憶は、どれも壮絶だ。あの英霊は——一人で、これだけの神と戦ったのか。","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"type":"end","bg_key":"bg_road_day","text":"軍神アレスの試練を乗り越え、剣を手に入れた。英霊の記憶の中のアレスは、敵でありながら、どこか気の良い武人だった。「次に会う時は、逃げずに最初から来いよ」その言葉を胸に刻み、次の石碑を目指す。","params":{"type":"end","result":"success","bg":"bg_road_day"},"next":"end_failure","choices":[]},"end_failure":{"type":"end","bg_key":"bg_memory_forest","text":"アレスの大剣に叩き伏せられ、泥の中に倒れた。雨の音だけが響く中、意識が遠くなっていく。アレスの声が、遠くから聞こえた。「まだ……足りねぇな」","params":{"type":"end","result":"failure"},"choices":[]}}}'::jsonb, rewards = '{"gold":3500,"exp":450,"reputation":25}'::jsonb WHERE id = 6018;

-- quest_6019_main_ep19.md (18 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","text":"英霊の導きに従い、出雲へ向かった。古き神々の信仰が息づく祐地は穏やかで、大社の境内には参拝者が絶えない。街の老人が教えてくれた。「北の山奥に、誰も行かない谷がある。　霧が深くて道がわからないが——光る石を見た者がいる」","next":"text_izumo","choices":[{"label":"続ける","next":"text_izumo"}]},"text_izumo":{"type":"text","bg_key":"bg_mountain","text":"出雲の北に連なる山脈に分け入った。杉の大木が空を覆い、昼でも薄暗い。獣道すら途切れる場所まで来ると、人間の気配は完全に消えた。鳥の声だけが、静かに響いている。","next":"text_mountain_path","choices":[{"label":"続ける","next":"text_mountain_path"}]},"text_mountain_path":{"type":"text","bg_key":"bg_mountain","text":"山道は険しかった。崩れかけた岩場を越え、急な斜面を登る。木の根に足を取られ、何度も転びそうになった。だが——腕に浮かぶ石碑の紋様が、正しい道を示し続けている。紋様が強く光る方へ、進んだ。","next":"text_fog","choices":[{"label":"続ける","next":"text_fog"}]},"text_fog":{"type":"text","bg_key":"bg_mountain","text":"標高が上がるにつれ、霧が濃くなった。手を伸ばせば目の前すら見えない白い世界。音も吸い込まれ、自分の足音だけが反響する。この霧は自然のものではない。英霊の石碑が——無関係な者を遠ざけているのだ。","next":"text_shrine_gate","choices":[{"label":"続ける","next":"text_shrine_gate"}]},"text_shrine_gate":{"type":"text","bg_key":"bg_mountain_shrine","bgm":"bgm_quest_tense","text":"霧を抜けると、突然視界が開けた。谷間の底に——朽ちた鳥居が立っていた。注連縄は切れ、苔に覆われている。だがその奥に、微かな光が見える。誰にも知られずに、何千年もここで待ち続けていたのだ。","next":"text_valley","choices":[{"label":"続ける","next":"text_valley"}]},"text_valley":{"type":"text","bg_key":"bg_mountain_shrine","text":"鳥居をくぐり、谷の奥へ進んだ。清流が岩を縫って流れている。苔むした石段が、谷の底へ続いていた。石段の終着点に——石碑が立っていた。月光のような銀色の光を放っている。夜ではないのに——この谷だけは、月に照らされていた。","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"type":"text","bg_key":"bg_heroic_stele","text":"石碑に近づいた。表面に文字が浮かび上がる。「此処に、英霊の記憶を封じる。　継承者よ。触れよ。　月光の試練を越え、力の欠片を受け継げ」覚悟を決めて——石碑に手を触れた。","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"type":"text","bg_key":"bg_heroic_stele","text":"意識が飛んだ。白い光が銀に変わり——気づくと、月明かりの山道に立っていた。英霊の記憶。この山で、英霊は追い詰められた。","next":"text_memory_mountain","choices":[{"label":"続ける","next":"text_memory_mountain"}]},"text_memory_mountain":{"type":"text","bg_key":"bg_memory_mountain","text":"記憶が再生される。英霊は、月夜の山道を駆けていた。木々の間から——銀色の矢が飛んでくる。音もなく。気配もなく。ただ正確に、急所を狙って射抜いてくる。どの木の陰にも、どの岩の裏にも——銀色の瞳が光っていた。狩りの女神に——標的にされていた。","next":"text_artemis_appear","choices":[{"label":"続ける","next":"text_artemis_appear"}]},"text_artemis_appear":{"type":"text","bg_key":"bg_memory_mountain","bgm":"bgm_battle_strong","text":"月光の中に、影が現れた。銀の髪。冷たい瞳。背に銀の弓を負い、白い狩衣を纏っている。女神アルテミス——月と狩りを司る神。狩猟を司る女神にして、最も正確な射手。その矢は——一度も的を外したことがないという。","next":"text_artemis_voice","choices":[{"label":"続ける","next":"text_artemis_voice"}]},"text_artemis_voice":{"type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","text":"アルテミスが弓を構えた。静かな声。感情を排した、研ぎ澄まされた声。「狩りの作法を教えよう。　獲物は——逃げれば追う。　隠れれば見つける。　立ち向かえば——射抜く。　英霊は、三つ目を選んだ。　お前はどうする？」","next":"text_artemis_challenge","choices":[{"label":"続ける","next":"text_artemis_challenge"}]},"text_artemis_challenge":{"type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","text":"「答えは聞くまでもないか。　その目を見ればわかる。　——良いだろう。　月の狩りに、挑む勇気は認める」銀の弓が引き絞られた。月光が矢に凝縮される。「だが——覚悟だけでは、矢は止められない」","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_memory_mountain","bgm":"bgm_spot_final_boss","text":"女神アルテミスとの戦闘！月光の矢を掻い潜り、狩りの女神を打ち倒せ！","enemy_group_id":"9052","next":"text_artemis_defeat","battle_success_next":"text_artemis_defeat","choices":[{"label":"続ける","next":"text_artemis_defeat"}]},"text_artemis_defeat":{"type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","text":"銀の弓の弦が——断ち切られた。アルテミスが弓を下ろし、初めて——僅かに、口元が緩んだ。「……英霊と同じだ。　追い詰めても、追い詰めても、前に出てくる。　人間の、そういうところが——厄介だ」月光に溶けるように、アルテミスの姿が消えた。「鎧はお前に預ける。　——次の狩りを、楽しみにしている」","next":"text_armor","choices":[{"label":"続ける","next":"text_armor"}]},"text_armor":{"type":"text","bg_key":"bg_mountain_shrine","text":"意識が現実に戻った。石碑の足元に——鎧が置かれていた。銀色に輝く鎧。月光を編み込んだような繊細な意匠。手に取ると、驚くほど軽い。だが、確かな守りの力が宿っている。女神の鎧。英霊がアルテミスから勝ち取った遺産の一つ。","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","text":"山を下り、出雲の街に戻った。手の中の鎧が、月光のように淡く光っている。四つの遺産のうち、また一つを手にした。ハデスの護符。アレスの剣。アルテミスの鎧。残るは——レガリアの遺跡に眠る、最後の記憶。","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"type":"end","bg_key":"bg_road_day","text":"女神アルテミスの試練を乗り越え、鎧を手に入れた。狩りの女神は手強かった。だが——最後の微笑みには、敵意はなかった。英霊は、これだけの神々と渡り合ってきたのだ。自分はその遺産を受け継ぎ、先へ進む。最後の石碑が待っている。","params":{"type":"end","result":"success","bg":"bg_road_day"},"next":"end_failure","choices":[]},"end_failure":{"type":"end","bg_key":"bg_memory_mountain","text":"銀の矢が胸を貫いた。月光の中に倒れ、意識が消えていく。遠くで——アルテミスの声が聞こえた。「まだ……獲物ではなかったか」","params":{"type":"end","result":"failure"},"choices":[]}}}'::jsonb, rewards = '{"gold":3500,"exp":450,"reputation":25}'::jsonb WHERE id = 6019;

-- quest_6020_main_ep20.md (23 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","text":"英霊の遺産を集める旅の、最後の行程。レガリア郊外にある古代の遺跡。かつて何の遺跡かもわからなかった場所が、今は——最後の石碑が眠る場所だとわかっている。ここに、英霊の最後の記憶がある。そして——全能神ゼウスが待っている。","next":"text_regalia","choices":[{"label":"続ける","next":"text_regalia"}]},"text_regalia":{"type":"text","bg_key":"bg_road_day","text":"レガリアの街を抜け、郊外へ向かった。王都は完全に復興し、白亜の城壁は以前よりも立派にそびえている。この街の人々のために——この戦いを終わらせなければ。","next":"text_outskirts","choices":[{"label":"続ける","next":"text_outskirts"}]},"text_outskirts":{"type":"text","bg_key":"bg_ruins_field","text":"レガリアの郊外。丘陵地帯の先に、古い石造りの遺跡が見えた。風化した柱。崩れかけた壁。かつては何かの神殿だったのだろう。だが——この遺跡には、英霊が最後の記憶を封じた石碑がある。","next":"text_ruins_entrance","choices":[{"label":"続ける","next":"text_ruins_entrance"}]},"text_ruins_entrance":{"type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_crisis","text":"遺跡の入口に立った。他の石碑がある場所とは空気が違う。緊張ではない。重圧。ここに封じられた記憶は、英霊にとって最後の戦いだった。深呼吸をして、遺跡の中に足を踏み入れた。","next":"text_descent","choices":[{"label":"続ける","next":"text_descent"}]},"text_descent":{"type":"text","bg_key":"bg_catacombs","text":"石段を下りていく。壁面の壁画が他の遺跡とは異なっていた。二人の人間が背中を合わせて戦う姿。一人は剣を、もう一人は盾を構えている。二人の前に——巨大な光の存在が立ちはだかっている。雷を纏った、天空の王の姿。","next":"text_final_chamber","choices":[{"label":"続ける","next":"text_final_chamber"}]},"text_final_chamber":{"type":"text","bg_key":"bg_boss_altar","text":"最奥の部屋に辿り着いた。今までの石碑の部屋よりも遥かに広い。天井にはっきりと空が見える。崩れた天井から、陽光が一本の柱のように降り注いでいた。その光の中に——最後の石碑が立っていた。他のどの石碑よりも大きく、強い光を放っている。","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"type":"text","bg_key":"bg_heroic_stele","text":"石碑に近づいた。表面の文字が、今までよりも力強く輝く。「此処に、英霊の最後の記憶を封じる。　継承者よ。触れよ。　全てを終わらせる力を——受け継げ」これが、最後の試練。覚悟を決めて——石碑に、手を触れた。","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"type":"text","bg_key":"bg_heroic_stele","text":"意識が飛んだ。今までで最も深く、最も鮮明に。目を開けると——広い平原に立っていた。空は暗く、雷鳴が轟いている。そして——隣に、誰かが立っていた。","next":"text_memory_gawain","choices":[{"label":"続ける","next":"text_memory_gawain"}]},"text_memory_gawain":{"type":"text","bg_key":"bg_memory_gawain","text":"記憶の中の英霊の隣に——一人の騎士がいた。額の傷跡。刃こぼれした長剣。砂埃を被った甲冑。——ガウェイン。英霊と共に戦った騎士。あの老騎士の、若き日の姿がそこにあった。","next":"text_memory_comrade","choices":[{"label":"続ける","next":"text_memory_comrade"}]},"text_memory_comrade":{"type":"text","bg_key":"bg_memory_gawain","text":"記憶の中のガウェインが、英霊に声をかけた。「相棒。あの雷の野郎が最後だ。　こいつを倒せば——終わる。全部、終わる」先代の英霊が頷いた。二人は剣を構えた。その背中は——かつて見た、あの老騎士の背中と重なった。ガウェインは、英霊の時代からずっと——人間のために戦い続けていたのだ。","next":"text_zeus_appear","choices":[{"label":"続ける","next":"text_zeus_appear"}]},"text_zeus_appear":{"type":"text","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","text":"雷鳴が一際大きく轟いた。雲の中から——巨大な存在が降りてくる。白い髭。威厳に満ちた顔。全身を雷光が包み、手には稲妻の槍を握っている。全能神ゼウス——神々の王にして、天空の支配者。全ての神の頂点に立つ存在。英霊が最後に戦い、辛くも退けた相手——その記憶が、今、目の前に再現される。","next":"text_zeus_voice","choices":[{"label":"続ける","next":"text_zeus_voice"}]},"text_zeus_voice":{"type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","text":"ゼウスが見下ろした。雷鳴のような声が、空間を震わせる。「また来たか、人間よ。　英霊は我を退けた。だが——倒しはしなかった。　神は不滅。天は永遠。　お前たちの抵抗は、嵐の前の蝋燭に過ぎぬ」","next":"text_zeus_challenge","choices":[{"label":"続ける","next":"text_zeus_challenge"}]},"text_zeus_challenge":{"type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","text":"「だが——認めよう。　人間には、我を苛立たせるだけの力がある。　ならば見せてみよ。　英霊を超える力があるのかどうか——　この場で証明せよ！」稲妻の槍が天に掲げられた。空全体が白く輝き、雷鳴が連続して轟く。","next":"check_items","choices":[{"label":"続ける","next":"check_items"}]},"check_items":{"type":"check_item","bg_key":"bg_memory_gawain","text":"英霊の遺産が反応している——","params":{"type":"check_item","items":[505,506,507],"success_node":"text_relics_glow","fail_node":"text_relics_missing"},"next":"text_relics_glow","choices":[{"label":"続ける","next":"text_relics_glow"}]},"text_relics_glow":{"type":"text","bg_key":"bg_memory_gawain","text":"冥王の護符が闇の光を放った。軍神の剣が赤い光を放った。女神の鎧が銀色に光り始めた。三つの遺産が共鳴し、全身を包む光の鎧となった。英霊が集めた神々の力——その加護が、継承者の体に宿る。ゼウスの雷を受け止められる。——いける。","next":"battle_weak","choices":[{"label":"続ける","next":"battle_weak"}]},"battle_weak":{"type":"battle","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","text":"全能神ゼウスとの最終決戦！英霊の遺産の加護を纏い、神々の王を打ち倒せ！","enemy_group_id":"9053","next":"text_zeus_defeat","battle_success_next":"text_zeus_defeat","choices":[{"label":"続ける","next":"text_zeus_defeat"}]},"text_zeus_defeat":{"type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","text":"稲妻の槍が——砕けた。ゼウスの巨体が揺らぎ、膝をついた。雷鳴が止み、空に静寂が戻る。「……馬鹿な。人間が……二度までも……」ゼウスが顔を上げた。その目に——怒りではなく、困惑があった。「英霊は我を退けた。　そしてお前もまた——　なぜだ。なぜ人間は、神を超えようとする？」","next":"text_dawn_sword","choices":[{"label":"続ける","next":"text_dawn_sword"}]},"text_dawn_sword":{"type":"text","bg_key":"bg_boss_altar","text":"意識が現実に戻った。石碑が砕け散り、光の粒が舞っている。その光が凝縮し——一振りの剣となった。蒼く輝く剣。刃に刻まれた紋様が、夜明けの空のように煌めいている。蒼暁の剣——英霊が神を退けた時に生まれた、人間の意志の結晶。手に取った。軽く、温かく——しっくりと手に馴染んだ。","next":"text_epilogue","choices":[{"label":"続ける","next":"text_epilogue"}]},"text_epilogue":{"type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","text":"遺跡を出ると、夜明けだった。東の空が蒼く染まり、やがて金色に変わっていく。新しい一日が始まる。英霊は、神と戦い、人間の未来を勝ち取った。その記憶と遺産は、次の世代へ受け継がれた。蒼暁の剣を掲げた。朝日が刃に反射し、蒼い光が空に伸びた。神の審判は終わった。人間は——自分たちの手で、未来を切り拓いた。","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"type":"end","bg_key":"bg_road_day","text":"全能神ゼウスを打ち破り、蒼暁の剣を手にした。英霊の記憶と共に、神々の審判から世界を救った。四つの首都は守られ、人々は生き続けている。この剣は——人間が諦めなかった証だ。英霊から受け継いだ意志と、仲間と共に戦い抜いた記憶が刻まれている。新しい朝が来た。世界は——自由だ。","params":{"type":"end","result":"success","bg":"bg_road_day"},"next":"end_failure","choices":[]},"end_failure":{"type":"end","bg_key":"bg_memory_gawain","text":"ゼウスの雷に打たれ、地に伏した。全能神の声が、遠雷のように響く。「まだ……足りぬか。人間よ」意識が——消えていく。","params":{"type":"end","result":"failure"},"next":"text_relics_missing","choices":[]},"text_relics_missing":{"type":"text","bg_key":"bg_memory_gawain","text":"英霊の遺産が——足りない。三つ全ての力が揃っていなければ、神々の加護は完全にはならない。ゼウスの力が増幅された。全能神の雷が、さらに苛烈になっていく。加護なしで、全力のゼウスに挑むことになる。——覚悟を決めるしかない。","next":"battle_strong","choices":[{"label":"続ける","next":"battle_strong"}]},"battle_strong":{"type":"battle","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","text":"全能神ゼウスとの最終決戦！遺産の加護なしで、全力の神に挑め！","enemy_group_id":"9054","battle_success_next":"text_zeus_defeat","choices":[{"label":"続ける","next":"text_zeus_defeat"}]}}}'::jsonb, rewards = '{"gold":15000,"exp":1000,"reputation":50}'::jsonb WHERE id = 6020;

